import java.util.stream.Stream;

public class StreamProcessingExample {
 public static void main(String[] args) {
 // Create a stream of integers
 Stream<Integer> stream = Stream.of(1, 2, 3, 4, 5);

 // Process the stream
 stream.map(x -> x * 2)
 .filter(x -> x > 5)
 .forEach(System.out::println);
 }
}
